+/// Compressed Sparse Row representation of a symmetric matrix.
+#[derive(Debug, Clone)]
+pub struct SparseMatrix {
+    /// Row pointer: row_ptr[i]..row_ptr[i+1] are the entries in row i.
+    pub row_ptr: Vec<usize>,
+    /// Column indices.
+    pub col_idx: Vec<usize>,
+    /// Non-zero values.
+    pub values: Vec<f64>,
+    /// Matrix dimension.
+    pub n: usize,
+}
+
+/// Result of eigendecomposition.
+#[derive(Debug, Clone)]
+pub struct EigenResult {
+    /// Eigenvalues (sorted ascending).
+    pub eigenvalues: Vec<f64>,
+    /// Eigenvectors (one per eigenvalue).
+    pub eigenvectors: Vec<Vec<f64>>,
+    /// Number of Lanczos iterations used.
+    pub iterations: usize,
+    /// Whether convergence was achieved.
+    pub converged: bool,
+}
+
+/// Lanczos solver configuration.
+#[derive(Debug, Clone)]
+pub struct LanczosConfig {
+    /// Number of eigenpairs to compute.
+    pub k: usize,
+    /// Maximum Lanczos iterations.
+    pub max_iter: usize,
+    /// Convergence tolerance.
+    pub tol: f64,
+    /// Whether to reorthogonalize Lanczos vectors.
+    pub reorthogonalize: bool,
+}
+
+impl Default for LanczosConfig {
+    fn default() -> Self {
+        Self {
+            k: 4,
+            max_iter: 100,
+            tol: 1e-8,
+            reorthogonalize: true,
+        }
+    }
+}
+
+impl SparseMatrix {
+    /// Create empty n x n matrix.
+    pub fn new(n: usize) -> Self {
+        Self {
+            row_ptr: vec![0; n + 1],
+            col_idx: Vec::new(),
+            values: Vec::new(),
+            n,
+        }
+    }
+
+    /// Build graph Laplacian L = D - W from weighted edges.
+    pub fn from_edges(n: usize, edges: &[(usize, usize, f64)]) -> Self {
+        // Build adjacency lists
+        let mut adj: Vec<Vec<(usize, f64)>> = vec![Vec::new(); n];
+        let mut degree = vec![0.0f64; n];
+
+        for &(u, v, w) in edges {
+            if u < n && v < n && u != v {
+                adj[u].push((v, w));
+                adj[v].push((u, w));
+                degree[u] += w;
+                degree[v] += w;
+            }
+        }
+
+        // Sort adjacency for CSR
+        for row in &mut adj {
+            row.sort_by_key(|&(col, _)| col);
+        }
+
+        // Build CSR for L = D - W
+        let mut row_ptr = vec![0usize; n + 1];
+        let mut col_idx = Vec::new();
+        let mut values = Vec::new();
+
+        for i in 0..n {
+            // Diagonal: degree[i]
+            // Off-diagonal: -w for each neighbor
+
+            // Insert entries in column order, including diagonal
+            let mut entries: Vec<(usize, f64)> = Vec::new();
+
+            // Add off-diagonal entries
+            for &(j, w) in &adj[i] {
+                entries.push((j, -w));
+            }
+
+            // Add diagonal
+            entries.push((i, degree[i]));
+            entries.sort_by_key(|&(col, _)| col);
+
+            // Merge duplicates
+            let mut merged: Vec<(usize, f64)> = Vec::new();
+            for (col, val) in entries {
+                if let Some(last) = merged.last_mut() {
+                    if last.0 == col {
+                        last.1 += val;
+                        continue;
+                    }
+                }
+                merged.push((col, val));
+            }
+
+            for (col, val) in &merged {
+                col_idx.push(*col);
+                values.push(*val);
+            }
+            row_ptr[i + 1] = col_idx.len();
+        }
+
+        Self {
+            row_ptr,
+            col_idx,
+            values,
+            n,
+        }
+    }
+
+    /// Matrix-vector product y = A * x (auto-vectorization friendly).
+    pub fn matvec(&self, x: &[f64], y: &mut [f64]) {
+        assert!(x.len() >= self.n && y.len() >= self.n);
+        for i in 0..self.n {
+            let start = self.row_ptr[i];
+            let end = self.row_ptr[i + 1];
+            let mut sum = 0.0f64;
+            // Inner loop is contiguous access — compiler will auto-vectorize
+            for idx in start..end {
+                sum += self.values[idx] * x[self.col_idx[idx]];
+            }
+            y[i] = sum;
+        }
+    }
+
+    /// Matrix dimension.
+    #[inline]
+    pub fn dim(&self) -> usize {
+        self.n
+    }
+
+    /// Matrix dimension (alias for compatibility).
+    #[inline]
+    pub fn n(&self) -> usize {
+        self.n
+    }
+}
+
+// ── SIMD-friendly vector operations ─────────────────────────────────────
+
+/// Dot product with 4 independent accumulators for maximum ILP.
+/// Auto-vectorizes to NEON/AVX2 on contiguous slices.
+#[inline]
+fn dot(a: &[f64], b: &[f64]) -> f64 {
+    let n = a.len().min(b.len());
+    let mut s0 = 0.0f64;
+    let mut s1 = 0.0f64;
+    let mut s2 = 0.0f64;
+    let mut s3 = 0.0f64;
+    let mut i = 0;
+
+    // 8-wide with 4 accumulators — exploits ILP across FMA units
+    while i + 8 <= n {
+        s0 += a[i] * b[i] + a[i + 4] * b[i + 4];
+        s1 += a[i + 1] * b[i + 1] + a[i + 5] * b[i + 5];
+        s2 += a[i + 2] * b[i + 2] + a[i + 6] * b[i + 6];
+        s3 += a[i + 3] * b[i + 3] + a[i + 7] * b[i + 7];
+        i += 8;
+    }
+    // Remainder
+    while i < n {
+        s0 += a[i] * b[i];
+        i += 1;
+    }
+    s0 + s1 + s2 + s3
+}
+
+/// L2 norm.
+#[inline]
+fn norm(a: &[f64]) -> f64 {
+    dot(a, a).sqrt()
+}
+
+/// axpy: y = y + alpha * x (8-wide for auto-vectorization)
+#[inline]
+fn axpy(alpha: f64, x: &[f64], y: &mut [f64]) {
+    let n = x.len().min(y.len());
+    let mut i = 0;
+    while i + 8 <= n {
+        y[i] += alpha * x[i];
+        y[i + 1] += alpha * x[i + 1];
+        y[i + 2] += alpha * x[i + 2];
+        y[i + 3] += alpha * x[i + 3];
+        y[i + 4] += alpha * x[i + 4];
+        y[i + 5] += alpha * x[i + 5];
+        y[i + 6] += alpha * x[i + 6];
+        y[i + 7] += alpha * x[i + 7];
+        i += 8;
+    }
+    while i < n {
+        y[i] += alpha * x[i];
+        i += 1;
+    }
+}
+
+/// Scale vector: x = alpha * x
+#[inline]
+fn scale(alpha: f64, x: &mut [f64]) {
+    let n = x.len();
+    let chunks = n / 4;
+    let remainder = n % 4;
+
+    for i in 0..chunks {
+        let base = i * 4;
+        x[base] *= alpha;
+        x[base + 1] *= alpha;
+        x[base + 2] *= alpha;
+        x[base + 3] *= alpha;
+    }
+    for i in (chunks * 4)..(chunks * 4 + remainder) {
+        x[i] *= alpha;
+    }
+}
