+            // Vocals: 200 Hz + harmonics
+            let vocals = 0.4 * (2.0 * PI * 200.0 * t).sin()
+                + 0.15 * (2.0 * PI * 400.0 * t).sin()
+                + 0.08 * (2.0 * PI * 600.0 * t).sin();
