+/// In-place radix-2 FFT with precomputed twiddle table (avoids sin/cos per stage).
+/// Use for repeated FFTs of the same size (STFT).
+fn fft_with_twiddles(real: &mut [f64], imag: &mut [f64], twiddles: &TwiddleCache) {
+    let n = real.len();
