+            for frame in 0..num_frames {
+                for f in 0..stft_num_freq {
+                    let idx = frame * stft_num_freq + f;
+                    if f >= freq_bin_min && f <= freq_bin_max {
+                        mask[idx] = 1.0;
+                    } else {
+                        let dist = if f < freq_bin_min {
+                            (freq_bin_min - f) as f64
