+    /// Reconstruct accumulated audio per stem from all processed frames.
+    pub fn get_accumulated_stems(&self) -> Vec<(Stem, Vec<f64>)> {
+        self.priors
+            .iter()
+            .enumerate()
+            .map(|(i, (stem, _))| (*stem, self.accumulated[i].clone()))
+            .collect()
+    }
+}
